$socials = ['Instagram' => setting('footer_instagram'), 'Facebook' => setting('footer_facebook'), 'TikTok' => setting('footer_tiktok'), 'YouTube' => setting('footer_youtube')];
?>
<!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="theme-color" content="<?= e($primary) ?>"><meta name="description" content="<?= e(setting('branding_meta_description', setting('store_tagline'))) ?>"><title><?= e(setting('branding_meta_title', setting('store_name', 'NiagaKita'))) ?></title><?php if ($favicon): ?><link rel="icon" href="<?= url('/media/branding/' . $favicon) ?>"><?php endif ?><link rel="stylesheet" href="<?= asset('app.css') ?>"><style>:root{--primary:<?= e($primary) ?>;--accent:<?= e($accent) ?>;--paper:<?= e($bg) ?>}.brand-logo{max-width:<?= e(setting('branding_logo_width', 180)) ?>px}</style></head><body class="store-body"><a class="skip-link" href="#main-content">Lewati ke konten utama</a><?php if (setting('homepage_announcement_enabled', '1') === '1'): ?><?php $announcement = setting('homepage_announcement_text', 'Belanja lintas kategori · Pesan langsung lewat WhatsApp · Stok terpantau'); ?><div class="ticker"><?php if (setting('homepage_announcement_url')): ?><a href="<?= e(setting('homepage_announcement_url')) ?>"><?= e($announcement) ?></a><?php else: ?><?= e($announcement) ?><?php endif ?></div><?php endif ?><header class="store-header"><a class="store-brand" href="<?= url('/') ?>"><?php if ($logo): ?><img class="brand-logo" src="<?= url('/media/branding/' . $logo) ?>" alt="<?= e(setting('branding_logo_alt', setting('store_name'))) ?>"><?php endif ?><?php if (!$logo || setting('branding_show_name', '1') === '1'): ?><span><?= e(setting('store_name', 'NiagaKita')) ?></span><?php endif ?></a><button class="store-menu-toggle" type="button" aria-expanded="false" aria-controls="store-nav">Menu</button><nav id="store-nav"><a href="<?= url('/produk') ?>" <?= str_starts_with($path, '/produk') || str_starts_with($path, '/kategori') ? 'aria-current="page"' : '' ?>>Semua produk</a><a href="<?= url('/#kategori') ?>" <?= $path === '/' ? 'aria-current="page"' : '' ?>>Kategori</a><a href="<?= url('/keranjang') ?>" <?= $path === '/keranjang' ? 'aria-current="page"' : '' ?>>Keranjang <b><?= array_sum($_SESSION['cart'] ?? []) ?></b></a></nav></header><?php if ($m = flash('success')): ?><div class="store-notice" role="status" aria-live="polite"><?= e($m) ?></div><?php endif ?><?php if ($m = flash('error')): ?><div class="store-notice error" role="alert"><?= e($m) ?></div><?php endif ?><main id="main-content"><?= $content ?></main><footer class="store-footer footer-<?= e(setting('footer_layout', 'three')) ?>"><div><?php if (setting('footer_show_logo', '1') === '1' && $logoLight): ?><img class="footer-logo" src="<?= url('/media/branding/' . $logoLight) ?>" alt="<?= e(setting('branding_logo_alt', setting('store_name'))) ?>"><?php else: ?><strong><?= e(setting('store_name', 'NiagaKita')) ?></strong><?php endif ?><p><?= e(setting('footer_description', setting('store_tagline'))) ?></p></div><div><span>Navigasi</span><?php foreach ($footerLinks as $link): ?><a href="<?= e(str_starts_with($link['url'], '/') ? url($link['url']) : $link['url']) ?>"><?= e($link['label']) ?></a><?php endforeach ?></div><div><span>Hubungi</span><a href="https://wa.me/<?= e(setting('store_whatsapp')) ?>">WhatsApp</a><?php if (setting('footer_email')): ?><a href="mailto:<?= e(setting('footer_email')) ?>"><?= e(setting('footer_email')) ?></a><?php endif ?><p><?= nl2br(e(setting('store_address'))) ?></p><p><?= e(setting('footer_hours')) ?></p></div><div class="footer-bottom"><span><?= e(str_replace('{year}', date('Y'), setting('footer_copyright', '© {year} ' . setting('store_name') . '. Semua hak dilindungi.'))) ?></span><span><?php foreach ($socials as $label => $href): if ($href): ?><a href="<?= e($href) ?>" target="_blank" rel="noopener"><?= e($label) ?></a><?php endif; endforeach ?><?php if (setting('footer_show_powered', '1') === '1'): ?> · Powered by Zenhosta<?php endif ?></span></div></footer><script>const menu=document.querySelector('.store-menu-toggle'),nav=document.querySelector('#store-nav');menu?.addEventListener('click',()=>{const open=menu.getAttribute('aria-expanded')==='true';menu.setAttribute('aria-expanded',String(!open));nav.classList.toggle('is-open',!open)});</script></body></html>
